import React from 'react';
import '../styles/global.css';

const InputField = ({ label, type = 'text', value, onChange, name }) => {
  return (
    <div className="input-group">
      <label htmlFor={name}>{label}</label>
      <input
        id={name}
        name={name}
        type={type}
        value={value}
        onChange={onChange}
        className="popx-input"
      />
    </div>
  );
};

export default InputField;
